import{_ as e,o as a,c as t,O as r}from"./chunks/framework.bdcb0ee1.js";const p=JSON.parse('{"title":"Name Changes","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/name-changes.md","filePath":"administration/users/name-changes.md","lastUpdated":1773167266000}'),n={name:"administration/users/name-changes.md"},s=r('<h1 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h1><p>Name change requests allow members to request a new username, which must be approved by an administrator before it takes effect. This feature is managed under the <strong>User Management</strong> navigation group in the Admin CP.</p><img width="1949" height="455" alt="image" src="https://github.com/user-attachments/assets/d89c71cf-32f0-46d6-9c18-a5f8e4cb0ee9"><nav class="table-of-contents"><ul><li><a href="#how-it-works">How it works</a></li><li><a href="#submitting-a-request">Submitting a request</a></li><li><a href="#reviewing-requests">Reviewing requests</a><ul><li><a href="#approving-a-request">Approving a request</a></li><li><a href="#denying-a-request">Denying a request</a></li></ul></li></ul></nav><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ol><li>A member submits a name change request from their profile, providing their desired new username and a reason for the change.</li><li>The request appears in the Admin CP under <strong>Name Changes</strong> as a pending request.</li><li>An administrator reviews the request and either approves or denies it.</li></ol><h2 id="submitting-a-request" tabindex="-1">Submitting a request <a class="header-anchor" href="#submitting-a-request" aria-label="Permalink to &quot;Submitting a request&quot;">​</a></h2><p>Members can request a name change from their profile page. They must provide:</p><ul><li><strong>Username</strong> — the new username they would like. Must be unique on the board, and can only contain letters, numbers, dashes and underscores.</li><li><strong>Reason</strong> — a short explanation for the name change (up to 255 characters).</li></ul><p>Only one pending request can be active at a time. The member must wait for a decision before submitting another.</p><h2 id="reviewing-requests" tabindex="-1">Reviewing requests <a class="header-anchor" href="#reviewing-requests" aria-label="Permalink to &quot;Reviewing requests&quot;">​</a></h2><p>In the Admin CP, the name changes page shows all pending requests. Each entry displays the member&#39;s current username, their requested username and the reason provided.</p><h3 id="approving-a-request" tabindex="-1">Approving a request <a class="header-anchor" href="#approving-a-request" aria-label="Permalink to &quot;Approving a request&quot;">​</a></h3><p>When you approve a name change:</p><ul><li>The member&#39;s username is immediately updated to the new name.</li><li>The request is marked as approved with a timestamp.</li></ul><h3 id="denying-a-request" tabindex="-1">Denying a request <a class="header-anchor" href="#denying-a-request" aria-label="Permalink to &quot;Denying a request&quot;">​</a></h3><p>When you deny a name change:</p><ul><li>The member&#39;s username remains unchanged.</li><li>The request is marked as denied with a timestamp.</li><li>The member is free to submit a new request.</li></ul>',18),i=[s];function o(h,u,m,l,d,c){return a(),t("div",null,i)}const q=e(n,[["render",o]]);export{p as __pageData,q as default};
